import { describe, it, expect } from "vitest";
import { quote, claim, createPolicy } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("quote", () => {
    it.todo("should return 5 G (processing fee only) for an empty item list");
    it.todo("should return base premium plus processing fee for a single sword (new customer, first contract)");
    it.todo("should return base premium plus processing fee for a single amulet (new customer, first contract)");
    it.todo("should return combined base premiums plus processing fee for a sword and an amulet (new customer)");
    it.todo("should apply cursed surcharge (50 %) to the affected item's base premium only");
    it.todo("should apply high-enchantment surcharge (30 %) for enchantment level >= 5");
    it.todo("should apply loyalty discount (20 %) for customers with >= 2 years with MHPCO");
    it.todo("should apply follow-up contract discount (15 %) on the second quote");
    it.todo("should apply block pricing (60 G) for exactly 3 alike components");
    it.todo("should round the final premium up (in the MHPCO's favor)");
  });

  describe("claim", () => {
    it.todo("should reimburse full damage minus the 100 G deductible for a standard item");
    it.todo("should apply a separate 100 G deductible per damaged item in the same incident");
    it.todo("should reimburse at 50 % of damage for items with enchantment >= 8 (then deductible)");
    it.todo("should fully reimburse damage to dragon-material items (then deductible)");
    it.todo("should apply the 50 % rule (not full reimbursement) when both clauses apply");
    it.todo("should cap total payout at twice the insurance sum across successive claims");
    it.todo("should round the final payout down (in the MHPCO's favor)");
  });
});

