const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

export const quote = (_customer: unknown, items: unknown[]): number => {
  const totalBase = items.reduce((sum, rawItem) => {
    const item = rawItem as { type: string };
    return sum + BASE_PREMIUMS[item.type];
  }, 0);
  const cursedSurcharge = items.reduce((sum, rawItem) => {
    const item = rawItem as { type: string; cursed: boolean };
    return sum + (item.cursed ? BASE_PREMIUMS[item.type] * 0.5 : 0);
  }, 0);
  return totalBase + cursedSurcharge + totalBase * FIRST_INSURANCE_SURCHARGE + PROCESSING_FEE;
};

export const createPolicy = (items: unknown[]): unknown => {
  return undefined as unknown;
};

export const claim = (policy: unknown, incident: unknown): unknown => {
  return undefined as unknown;
};

