  const loyaltyDiscount = c.yearsWithMHPCO >= 2 ? totalBase * 0.2 : 0;
  return totalItemPremium + totalBase * FIRST_INSURANCE_SURCHARGE - loyaltyDiscount + PROCESSING_FEE;
};

