export const claim = (policy: unknown, incident: unknown): unknown => {
  const items = policy as { type: string; enchantment?: number }[];
  const { damages } = incident as { damages: { itemType: string; amount: number }[] };
  const payout = damages.reduce((sum, damage) => {
    const item = items.find(i => i.type === damage.itemType);
    const reimbursable = item && (item.enchantment ?? 0) >= 8 ? damage.amount * 0.5 : damage.amount;
    return sum + reimbursable - 100;
  }, 0);
  return { payout };
};

